const runResponse = $('Create Run').item?.json ?? {};
const run = runResponse.data?.run ?? runResponse.run ?? runResponse;
if (!run || !run.id) {
  throw new Error('AISMR workflow could not load run details.');
}
const turnResponse = $('Get Turn').item?.json ?? {};
const turn = turnResponse.data?.turn ?? turnResponse.turn ?? turnResponse;
if (!turn || typeof turn !== 'object') {
  throw new Error('AISMR workflow could not load conversation turn details.');
}
const turnContent = typeof turn.content === 'string' ? turn.content.trim() : '';
if (!turnContent) {
  throw new Error('AISMR workflow could not find user turn content.');
}
const sessionIdRaw = turn.sessionId ?? turn.session_id ?? turn.metadata?.sessionId ?? null;
const sessionId = typeof sessionIdRaw === 'string' ? sessionIdRaw.trim().toLowerCase() : null;
if (!sessionId) {
  throw new Error('AISMR workflow could not determine sessionId from turn record.');
}
const runId = $('Validate Inputs').item.json.runId;
const personaId = run.personaId ?? run.persona_id ?? run.metadata?.personaId ?? 'ideagenerator';
const projectId = run.projectId ?? run.project_id ?? run.metadata?.projectId ?? 'aismr';
const outputSchema = {
  type: 'object',
  properties: {
    userIdea: {
      type: 'string',
      description: 'Normalized base object (lowercase singular) applied to every idea.'
    },
    ideas: {
      type: 'array',
      description: 'Exactly 12 unique AISMR-ready concepts in Title Case descriptor + singular object format.',
      items: {
        type: 'object',
        properties: {
          idea: {
            type: 'string',
            description: 'Title Case descriptor + singular object (two words, descriptor is one word).'
          },
          vibe: {
            type: 'string',
            description: '2-4 sentence explanation covering emotion, hook, texture, feasibility, replay value, and environment potential.'
          }
        },
        required: ['idea', 'vibe'],
        additionalProperties: false
      },
      minItems: 12,
      maxItems: 12
    }
  },
  required: ['userIdea', 'ideas'],
  additionalProperties: false
};
return {
  json: {
    sessionId,
    runId,
    run,
    projectId,
    personaId,
    userInput: turnContent,
    turn,
    turnId: turn.id ?? $('Validate Inputs').item.json.turnId,
    outputSchema: JSON.stringify(outputSchema),
  },
};

function tryParse(value) {
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch (error) {
      return null;
    }
  }
  return null;
}
function extractStructured(value) {
  if (value == null) {
    return null;
  }
  if (typeof value === 'string') {
    const parsed = tryParse(value);
    if (parsed) {
      return extractStructured(parsed);
    }
    return null;
  }
  if (Array.isArray(value)) {
    for (const item of value) {
      const extracted = extractStructured(item);
      if (extracted) return extracted;
    }
    return null;
  }
  if (typeof value === 'object') {
    if (typeof value.userIdea === 'string' && Array.isArray(value.ideas)) {
      return value;
    }
    const candidates = [value.output, value.result, value.structuredOutput, value.data, value.response, value.content];
    for (const candidate of candidates) {
      const extracted = extractStructured(candidate);
      if (extracted) return extracted;
    }
  }
  return null;
}
const original = $json ?? {};
if (original.error) {
  const reason = typeof original.error === 'object' ? (original.error.message || original.error.reason || JSON.stringify(original.error)) : String(original.error);
  throw new Error(`Mylo MCP Bot failed: ${reason}`);
}
const structured = extractStructured(original);
if (!structured) {
  throw new Error('AISMR Mylo response did not include structured output.');
}
if (typeof structured.userIdea !== 'string' || structured.userIdea.trim().length === 0) {
  throw new Error('AISMR Mylo response missing userIdea string.');
}
if (!Array.isArray(structured.ideas) || structured.ideas.length !== 12) {
  throw new Error('AISMR Mylo response must contain exactly 12 ideas.');
}
structured.ideas.forEach((idea, index) => {
  if (!idea || typeof idea !== 'object') {
    throw new Error(`Idea #${index + 1} is not an object.`);
  }
  if (typeof idea.idea !== 'string' || idea.idea.trim().length === 0) {
    throw new Error(`Idea #${index + 1} missing idea text.`);
  }
  if (typeof idea.vibe !== 'string' || idea.vibe.trim().length === 0) {
    throw new Error(`Idea #${index + 1} missing vibe text.`);
  }
});
const context = $('Assemble Context').item?.json ?? {};
const runId = context.runId;
const sessionId = context.sessionId;
const timestamp = new Date().toISOString();
const runUpdate = {
  status: 'ideas_complete',
  result: structured,
  completedAt: timestamp
};
return {
  json: {
    sessionId,
    runId,
    structured,
    runUpdate,
    telemetry: {
      myloResponse: original
    }
  }
};

const prepared = $('Prepare Response').item?.json ?? {};
return {
  json: {
    sessionId: prepared.sessionId ?? null,
    runId: prepared.runId ?? null,
    ideas: prepared.structured?.ideas ?? [],
    userIdea: prepared.structured?.userIdea ?? null,
    result: prepared.structured ?? null,
    telemetry: prepared.telemetry ?? {}
  }
};
